/* ═══════════════════════════════════════════════
   DATA: Ginecología 1 — 100 preguntas
   Para agregar más bancos, copia data-TEMPLATE.js
   y sigue las instrucciones dentro.
═══════════════════════════════════════════════ */
var ENURM_GINECO1 = [
 {id:'g1_1',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Dónde tiene lugar la fecundación del óvulo?',opts:['Porción ístmica de la trompa','Porción ampular de la trompa','Cavidad uterina','Fimbrias'],ans:1,exp:'<b>Correcto:</b> La fecundación tiene lugar en la porción ampular de la trompa. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_2',type:'mc',diff:'easy',sub:'ginecologia',text:'¿En qué día tras la ovulación se produce la implantación del blastocisto en el endometrio?',opts:['Día 1-2','Día 3-4','Día 5-7','Día 10-12'],ans:2,exp:'<b>Correcto:</b> El óvulo fecundado se implanta en el endometrio el día 5-7 tras la ovulación, en fase de blastocisto. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_3',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Qué mecanismo previene la poliespermia una vez que un espermatozoide penetra en el ovocito?',opts:['Liberación de oxitocina','Reacciones cortical y de zona','Aumento de progesterona','Cierre del cuello uterino'],ans:1,exp:'<b>Correcto:</b> Las reacciones cortical y de zona consisten en la liberación de enzimas lisosómicas que modifican la membrana del ovocito y la zona pelúcida, impidiendo la entrada de nuevos espermatozoides. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_4',type:'mc',diff:'easy',sub:'ginecologia',text:'¿A partir de qué semana se identifica la placenta y qué elementos la forman?',opts:['Semana 4, solo elementos fetales','Semana 8, elementos maternos (decidua) y fetales (corion)','Semana 12, solo decidua','Semana 16, corion y amnios'],ans:1,exp:'<b>Correcto:</b> La placenta se identifica a partir de la semana 8 y se forma de decidua (materna) y corion (fetal). <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_5',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Qué mecanismo de transporte placentario utiliza la glucosa?',opts:['Difusión simple','Difusión facilitada','Transporte activo','Pinocitosis'],ans:1,exp:'<b>Correcto:</b> La glucosa pasa a través de la placenta por difusión facilitada, usando transportadores sin gasto de energía. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_6',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es el mecanismo de transporte placentario de aminoácidos, hierro, calcio y vitaminas hidrosolubles?',opts:['Difusión simple','Difusión facilitada','Transporte activo','Paso directo por solución de continuidad'],ans:2,exp:'<b>Correcto:</b> Los aminoácidos y minerales como hierro y calcio se transportan por transporte activo, en contra de gradiente con gasto de ATP. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_7',type:'mc',diff:'easy',sub:'ginecologia',text:'¿Cuándo se detecta la HCG en sangre materna y cuándo es detectable en orina?',opts:['Semana 1 en sangre y semana 3 en orina','Al final de la semana 3 en sangre y semana 5 de amenorrea en orina','Semana 6 en sangre y semana 8 en orina','Semana 10 en sangre y semana 12 en orina'],ans:1,exp:'<b>Correcto:</b> La HCG se detecta en sangre al final de la semana 3 (8-9 días postovulación) y en orina en la semana 5 de amenorrea. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_8',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es la acción biológica principal de la gonadotropina coriónica (HCG)?',opts:['Estimular la producción de estriol fetal','Mantener el cuerpo lúteo y la secreción de progesterona las primeras 6-8 semanas','Inducir la maduración pulmonar fetal','Preparar las mamas para la lactancia'],ans:1,exp:'<b>Correcto:</b> La HCG tiene acción luteotrófica: mantiene el cuerpo lúteo y la secreción de progesterona durante las primeras 6-8 semanas de gestación. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_9',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuándo alcanza la HCG su pico máximo y cuándo estabiliza su meseta?',opts:['Pico en semana 5 y meseta en semana 10','Pico en semana 10 y meseta entre semanas 17-18','Pico en semana 15 y meseta en semana 20','Pico en semana 20 y meseta en semana 30'],ans:1,exp:'<b>Correcto:</b> La HCG alcanza su pico alrededor de la semana 10 (50.000 mUI/ml) y luego desciende hasta una meseta entre las semanas 17-18. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_10',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es la acción biológica del lactógeno placentario (HPL)?',opts:['Estimula la síntesis de progesterona','Es una hormona diabetógena que asegura el suministro de glucosa al feto y activa la lipólisis materna','Inhibe la secreción de insulina materna','Produce vasoconstricción periférica'],ans:1,exp:'<b>Correcto:</b> El HPL es una hormona diabetógena: se libera en respuesta a hipoglucemia, asegura glucosa al feto, activa la lipólisis y antagoniza la insulina en la segunda mitad del embarazo. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_11',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es el estrógeno más importante durante la gestación y qué indica su disminución?',opts:['Estradiol; indica insuficiencia ovárica','Estrona; indica preeclampsia','Estriol; está descendido en cromosomopatías y ausente en mola completa','Dietilestilbestrol; indica anomalía placentaria'],ans:2,exp:'<b>Correcto:</b> El estriol es el estrógeno más importante en la gestación, deriva de precursores fetales metabolizados por la placenta; sus niveles están disminuidos en cromosomopatías y ausentes en la mola completa. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_12',type:'mc',diff:'easy',sub:'ginecologia',text:'¿Cuál de los siguientes signos nunca puede considerarse fisiológico en una gestante?',opts:['Alcalosis respiratoria','Desviación del eje en el ECG','Soplo diastólico','Anemia dilucional'],ans:2,exp:'<b>Correcto:</b> El soplo diastólico, el aumento de transaminasas y el aumento de bilirrubina nunca son fisiológicos en la gestante. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_13',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Qué cambio cardiovascular se produce con mayor frecuencia durante el embarazo?',opts:['Aumento de la tensión arterial durante todo el embarazo','Disminución de la volemia','La volemia aumenta progresivamente hasta la semana 34-36 y se produce vasodilatación periférica generalizada','Disminución del gasto cardíaco'],ans:2,exp:'<b>Correcto:</b> Durante la gestación hay aumento progresivo de la volemia hasta la semana 34-36 y vasodilatación periférica generalizada; la TA disminuye en el 1° y 2° trimestre. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_14',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Qué cambio hematológico es característico del embarazo?',opts:['Aumento del hematocrito por encima del 40%','Anemia fisiológica dilucional con hemoglobina de unos 11 g/dl','Trombocitosis marcada','Disminución del fibrinógeno'],ans:1,exp:'<b>Correcto:</b> Se produce anemia fisiológica dilucional porque el volumen plasmático aumenta más que la masa eritrocitaria; la gestante maneja Hb ~11 g/dl y Hto ~34%. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_15',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Qué cambio renal funcional se produce durante la gestación?',opts:['Disminución del filtrado glomerular en un 40-50%','Aumento del filtrado glomerular en un 40-50% y disminución de creatinina, urea y ácido úrico en sangre','Insuficiencia renal aguda progresiva','Disminución del flujo plasmático renal'],ans:1,exp:'<b>Correcto:</b> El filtrado glomerular aumenta un 40-50%, por lo que los niveles de creatinina, urea, ácido úrico y aminoácidos disminuyen en sangre. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_16',type:'mc',diff:'easy',sub:'ginecologia',text:'¿Cuál es el principal método de diagnóstico prenatal durante el embarazo?',opts:['Amniocentesis','Biopsia corial','Ecografía','Cordocentesis'],ans:2,exp:'<b>Correcto:</b> El principal método de diagnóstico prenatal es la ecografía, recomendándose tres ecografías durante la gestación. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_17',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es el método más fiable para estimar la edad gestacional en la ecografía del primer trimestre?',opts:['Diámetro biparietal','Longitud cráneocaudal (CRL)','Longitud femoral','Fecha de última regla'],ans:1,exp:'<b>Correcto:</b> La medición de la longitud cráneocaudal (CRL) es el método más fiable de estimación de la edad gestacional en el primer trimestre. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_18',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es la malformación fetal más frecuente detectada en la ecografía del segundo trimestre?',opts:['Defectos del tubo neural','Cardiopatías congénitas','Malformaciones renales','Hendiduras labiopalatinas'],ans:1,exp:'<b>Correcto:</b> Las cardiopatías congénitas son las malformaciones fetales más frecuentes, seguidas de las malformaciones del sistema nervioso central. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_19',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es el principal marcador ecográfico de aneuploidía en el primer trimestre?',opts:['Ausencia de hueso nasal','Insuficiencia tricuspídea','Translucencia nucal','Pielectasia'],ans:2,exp:'<b>Correcto:</b> La translucencia nucal es el principal marcador ecográfico de aneuploidía, con una tasa de detección del 70-80%. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_20',type:'mc',diff:'medium',sub:'ginecologia',text:'¿A partir de qué índice de riesgo combinado se recomienda la realización de pruebas invasivas de diagnóstico citogenético?',opts:['Mayor de 1/100','Mayor de 1/270','Mayor de 1/500','Mayor de 1/1000'],ans:1,exp:'<b>Correcto:</b> Se recomienda la realización de pruebas diagnósticas citogenéticas con un índice de riesgo combinado por encima de 1/270. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_21',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es la tasa de detección del cribado combinado del primer trimestre (edad materna + bioquímica + translucencia nucal)?',opts:['50-60%','70-75%','85-90%','95-100%'],ans:2,exp:'<b>Correcto:</b> El cribado combinado permite detectar el 85-90% de los casos de trisomía 21. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_22',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es la complicación principal de la biopsia corial respecto a la amniocentesis?',opts:['Mayor riesgo de infección','Mayor riesgo de pérdida fetal y de falsos positivos por mosaicismos en tejido corial','Mayor dificultad técnica','No permite estudio citogenético'],ans:1,exp:'<b>Correcto:</b> Las complicaciones de la biopsia corial son abortos (1-1,5%) y falsos positivos por mosaicismos en tejido corial. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_23',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es la complicación más importante de la cordocentesis?',opts:['Amnionitis','Hemorragia transplacentaria (50%)','Defectos de extremidades','Pie equinovaro'],ans:1,exp:'<b>Correcto:</b> La complicación más importante de la cordocentesis es la hemorragia transplacentaria (50%), además de bradicardia, pérdida fetal, RPM e infección. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_24',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es el factor de riesgo más importante para el desarrollo de CIR tipo II?',opts:['Infecciones TORCH','Aneuploidías','Trastornos hipertensivos en la gestación','Consumo de tabaco'],ans:2,exp:'<b>Correcto:</b> Los trastornos hipertensivos en la gestación o previos a ella son el factor de riesgo más importante para el CIR tipo II (asimétrico). <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_25',type:'mc',diff:'hard',sub:'ginecologia',text:'En el CIR tipo II, ¿qué hallazgo Doppler es signo ominoso de sufrimiento fetal?',opts:['Aumento de resistencias en arteria umbilical','Vasodilatación de arteria cerebral media','Flujo ausente en ductus venoso','Disminución del flujo diastólico umbilical'],ans:2,exp:'<b>Correcto:</b> El flujo ausente en el ductus venoso es el signo más grave y ominoso de sufrimiento fetal en el CIR tipo II. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_26',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es el parámetro más fiable para valorar el estado real del feto durante el parto?',opts:['Registro cardiotocográfico','Pulsioximetría fetal','pH en microtoma de sangre fetal','Perfil biofísico'],ans:2,exp:'<b>Correcto:</b> La microtoma fetal (estudio del pH y gasometría de sangre del cuero cabelludo) es el parámetro más fiable para valorar el estado real del feto durante el parto. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_27',type:'mc',diff:'medium',sub:'ginecologia',text:'En la microtoma fetal intraparto, ¿qué conducta se toma ante un pH entre 7,20 y 7,25?',opts:['Continuar el parto sin intervención','Extracción fetal inmediata','Repetir microtoma en 15 minutos y valorar extracción en 1 hora si persiste','Administrar oxitocina'],ans:2,exp:'<b>Correcto:</b> Ante un pH entre 7,20 y 7,25 se repite la microtoma en 15 minutos; si persiste, se valora la extracción fetal en 1 hora. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_28',type:'mc',diff:'medium',sub:'ginecologia',text:'En el registro cardiotocográfico, ¿qué tipo de deceleraciones son fisiológicas y a qué se deben?',opts:['DIP tipo II; hipoxia fetal','DIP tipo III; compresión del cordón','DIP tipo I; estimulación vagal por compresión de la cabeza fetal','Deceleraciones variables; insuficiencia uteroplacentaria'],ans:2,exp:'<b>Correcto:</b> Los DIP tipo I (precoces) son síncronos con la contracción, fisiológicos, debidos a estimulación vagal por compresión de la cabeza fetal. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_29',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es la causa más frecuente del aborto espontáneo?',opts:['Insuficiencia istmicocervical','Síndrome antifosfolípido','Anomalías cromosómicas embrionarias','Infección por Mycoplasma'],ans:2,exp:'<b>Correcto:</b> La causa más frecuente de aborto son las anomalías cromosómicas embrionarias (trisomías, monosomía X, poliploidías). <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_30',type:'mc',diff:'easy',sub:'ginecologia',text:'¿Cuál es la primera causa de abortos de repetición tardíos?',opts:['Anomalías cromosómicas','Síndrome antifosfolípido','Insuficiencia istmicocervical','Infección por Toxoplasma'],ans:2,exp:'<b>Correcto:</b> La insuficiencia istmicocervical es la primera causa de abortos de repetición, sobre todo tardíos. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_31',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Qué riesgo específico existe en el aborto diferido y cómo se monitoriza?',opts:['Riesgo de sepsis; cultivos','Riesgo de coagulopatías (CID); productos de degradación del fibrinógeno','Riesgo de perforación uterina; ecografía','Riesgo de embarazo ectópico; HCG'],ans:1,exp:'<b>Correcto:</b> En el aborto diferido existe riesgo de coagulopatías (CID) por liberación de tromboplastinas placentarias, por lo que se determinan los productos de degradación del fibrinógeno. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_32',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es el tratamiento de la incompetencia cervical?',opts:['Reposo absoluto','Progesterona vaginal','Cerclaje cervical','Amniocentesis evacuadora'],ans:2,exp:'<b>Correcto:</b> El tratamiento de la incompetencia cervical es el cerclaje cervical, indicado entre las semanas 12-14 o antes de la semana 24 según los antecedentes. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_33',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es la localización más frecuente de la gestación ectópica?',opts:['Porción ístmica de la trompa','Porción ampular de la trompa (80%)','Ovario','Cérvix'],ans:1,exp:'<b>Correcto:</b> El 97% de los ectópicos son tubáricos y de ellos el 80% son ampulares. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_34',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es la técnica de elección para el diagnóstico de sospecha de gestación ectópica?',opts:['Laparoscopia','Culdocentesis','Ecografía transvaginal','TC abdominal'],ans:2,exp:'<b>Correcto:</b> La ecografía transvaginal es la técnica de elección para el diagnóstico de sospecha de gestación ectópica. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_35',type:'mc',diff:'hard',sub:'ginecologia',text:'¿Qué hallazgo anatomo-patológico en el contenido uterino es altamente sugestivo de gestación ectópica?',opts:['Vellosidades coriales inmaduras','Decidua con ausencia de vellosidades coriales (signo de Arias Stella)','Trofoblasto hiperplásico','Cuerpo lúteo hemorrágico'],ans:1,exp:'<b>Correcto:</b> El signo de Arias Stella (decidua con ausencia de vellosidades coriales) en el contenido uterino es altamente sugestivo, aunque no patognomónico, de gestación ectópica. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_36',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es el tratamiento de elección quirúrgico de la gestación ectópica?',opts:['Salpingotomía','Salpinguectomía por laparoscopia','Histerectomía','Laparotomía con salpingostomía'],ans:1,exp:'<b>Correcto:</b> El tratamiento quirúrgico preferido es la salpinguectomía (resección de la trompa) por vía laparoscópica, preservando la fertilidad con la otra trompa. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_37',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es la patogenia de la mola completa?',opts:['Fecundación de un óvulo normal por dos espermatozoides','Fecundación de un óvulo vacío por un espermatozoide 23X que duplica sus cromosomas; resultado 46XX con ambos X de origen paterno','División tardía de un embrión monocigoto','Anomalía cromosómica materna'],ans:1,exp:'<b>Correcto:</b> La mola completa resulta de la fecundación de un óvulo vacío por un espermatozoide 23X que duplica sus cromosomas (o dos espermatozoides); son casi siempre 46XX con ambos cromosomas de origen paterno. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_38',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es el síntoma más frecuente de la mola hidatiforme?',opts:['Dolor abdominal agudo','Hemorragia indolora con aspecto de "agua de lavar carne" (97%)','Náuseas y vómitos aislados','Expulsión de vesículas'],ans:1,exp:'<b>Correcto:</b> El síntoma más frecuente de la mola hidatiforme es la hemorragia indolora con aspecto de "agua de lavar carne" (97%). <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_39',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es el tratamiento de elección de la mola hidatiforme?',opts:['Histerectomía total inmediata','Quimioterapia con metotrexate','Evacuación uterina mediante legrado por aspiración','Observación expectante'],ans:2,exp:'<b>Correcto:</b> El tratamiento de elección de la mola hidatiforme es la evacuación uterina mediante legrado por aspiración. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_40',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es el patrón ecográfico característico de la mola hidatiforme?',opts:['Saco gestacional vacío','Imagen en copos de nieve/nevada con útero mayor que amenorrea','Masa anexial con líquido libre','Engrosamiento endometrial focal'],ans:1,exp:'<b>Correcto:</b> La ecografía muestra un patrón en "copos de nieve o nevada" con vesículas múltiples de pequeño tamaño, útero mayor que amenorrea y quistes tecaluteínicos. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_41',type:'mc',diff:'easy',sub:'ginecologia',text:'¿Cuál es la causa más frecuente de hemorragia en el tercer trimestre?',opts:['Abruptio placentae','Rotura de vasa previa','Placenta previa','Rotura uterina'],ans:2,exp:'<b>Correcto:</b> La placenta previa es la causa más frecuente de hemorragia en el tercer trimestre (incidencia 1/200 embarazos). <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_42',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Qué está contraindicado en el diagnóstico de la placenta previa?',opts:['Ecografía transabdominal','Tacto vaginal','Doppler de arterias uterinas','RMN pélvica'],ans:1,exp:'<b>Correcto:</b> Nunca debe realizarse un tacto vaginal ante sospecha de placenta previa porque puede romper la placenta y provocar una hemorragia fatal. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_43',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es el factor que más claramente se asocia con el abruptio placentae?',opts:['Multiparidad','Tabaquismo','Hipertensión arterial','Traumatismo abdominal'],ans:2,exp:'<b>Correcto:</b> La HTA es el factor que más claramente se asocia al abruptio placentae. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_44',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es la complicación más frecuente del abruptio placentae grave y su relevancia en la gestación?',opts:['Preeclampsia','Insuficiencia renal aguda','CID; el DPPNI es la causa más frecuente de CID en la gestación','Embolismo pulmonar'],ans:2,exp:'<b>Correcto:</b> El DPPNI provoca alteraciones de la coagulación en el 10% y constituye la causa más frecuente de CID en la gestación. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_45',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es la clínica característica de la rotura de vasa previa?',opts:['Hemorragia materna con buen estado fetal','Hemorragia de origen fetal con sufrimiento fetal agudo y mortalidad fetal muy elevada (75%), con buen estado materno','Hipertonía uterina sin hemorragia','Bradicardia materna'],ans:1,exp:'<b>Correcto:</b> La rotura de vasa previa produce hemorragia de origen fetal con sufrimiento fetal agudo secundario a anemia; mortalidad fetal muy elevada (75%) con buen estado materno. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_46',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es la consecuencia del prolapso de cordón con membranas rotas?',opts:['Requiere cesárea urgente por elevada mortalidad fetal','Se permite el parto vaginal en todos los casos','Se trata con tocólisis','Se realiza amnioinfusión'],ans:0,exp:'<b>Correcto:</b> El prolapso de cordón (cordón que sobrepasa la presentación con membranas rotas) requiere cesárea urgente porque la mortalidad fetal es elevada. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_47',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Qué es la placenta acreta y cuál es su tratamiento definitivo en caso de acretismo total?',opts:['Inserción velamentosa del cordón; cerclaje','Inserción de vellosidades en miometrio sin plano de separación con pared uterina; histerectomía','Placenta con lóbulos accesorios; extracción manual','Placenta que no se desprende por infección; antibióticos'],ans:1,exp:'<b>Correcto:</b> La placenta acreta es la inserción de vellosidades coriales en el miometrio sin plano de separación; si el acretismo es total, requiere histerectomía. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_48',type:'mc',diff:'medium',sub:'ginecologia',text:'¿En qué condición está indicada la indometacina para el polihidramnios y cuál es su limitación?',opts:['Se usa sin restricción de semanas','No debe administrarse más allá de la semana 34 ni más de 48-72 horas por riesgo de cierre del ductus','Solo se usa en el primer trimestre','Está contraindicada en el embarazo'],ans:1,exp:'<b>Correcto:</b> La indometacina reduce el líquido amniótico pero no debe administrarse más allá de la semana 34 ni más de 48-72 horas por riesgo de cierre precoz del ductus arterioso. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_49',type:'mc',diff:'easy',sub:'ginecologia',text:'¿Cuál es el síntoma más precoz y característico de la colestasis intrahepática gestacional?',opts:['Ictericia franca','Prurito generalizado e intenso, sobre todo palmoplantar, sin lesiones dermatológicas','Dolor en hipocondrio derecho','Coluria intensa'],ans:1,exp:'<b>Correcto:</b> El prurito generalizado e intenso, sobre todo palmoplantar y sin lesiones dermatológicas, con predominio nocturno es el síntoma más precoz de la colestasis intrahepática gestacional. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_50',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es la primera causa de mortalidad materna no obstétrica?',opts:['Tromboembolia pulmonar','Infección','Cardiopatías','Enfermedad renal'],ans:2,exp:'<b>Correcto:</b> Las cardiopatías son la primera causa de mortalidad materna no obstétrica, con una incidencia del 1-2%. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_51',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuándo debe realizarse el cribado de bacteriuria asintomática en la gestante?',opts:['Semanas 20-24','Primer trimestre (semanas 12-16)','Tercer trimestre','Solo si hay síntomas'],ans:1,exp:'<b>Correcto:</b> El cribado de bacteriuria asintomática se realiza mediante cultivo de orina durante el primer trimestre (semanas 12-16), coincidiendo con la primera analítica gestacional. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_52',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuándo debe realizarse el cultivo vaginal y rectal para la detección de Estreptococo del grupo B (SGB)?',opts:['Semanas 20-24','Semanas 28-32','Semanas 35-37','En el momento del parto'],ans:2,exp:'<b>Correcto:</b> El cultivo vaginal y rectal para SGB debe realizarse a todas las gestantes entre las semanas 35-37. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_53',type:'mc',diff:'easy',sub:'ginecologia',text:'¿Cuándo se realiza el test de O\'Sullivan (screening de diabetes gestacional)?',opts:['Semanas 12-16','Semanas 18-20','Semanas 24-28','Semanas 32-34'],ans:2,exp:'<b>Correcto:</b> El test de O\'Sullivan se realiza a todas las gestantes entre las semanas 24-28 (y en el primer trimestre si hay factores de riesgo). <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_54',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuáles son los criterios de positividad de la sobrecarga oral de glucosa (SOG con 100g) para diagnóstico de diabetes gestacional?',opts:['Un valor alterado es suficiente','Dos o más valores iguales o superiores a: basal 95, 1h 180, 2h 155, 3h 140 mg/dl','Glucemia basal mayor de 200 mg/dl','HbA1c mayor del 6,5%'],ans:1,exp:'<b>Correcto:</b> La SOG es positiva si dos o más valores son iguales o superiores a: basal 95, 1h 180, 2h 155, 3h 140 mg/dl. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_55',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es la malformación congénita más específica de la diabetes gestacional?',opts:['Transposición de grandes vasos','Síndrome de regresión caudal','Encefalocele','CIA'],ans:1,exp:'<b>Correcto:</b> El síndrome de regresión caudal es la malformación más específica (aunque no la más frecuente) de la diabetes gestacional. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_56',type:'mc',diff:'easy',sub:'ginecologia',text:'¿Cómo se define la preeclampsia?',opts:['HTA en cualquier momento del embarazo sin proteinuria','HTA después de la semana 20 con proteinuria mayor de 300 mg/24h, que no se prolonga más allá de la semana 12 posparto','HTA crónica con proteinuria previa al embarazo','Convulsiones en una gestante hipertensa'],ans:1,exp:'<b>Correcto:</b> La preeclampsia es HTA (>140/90) que se desarrolla después de la semana 20 con proteinuria >300 mg/24h, que remite en el puerperio. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_57',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál de los siguientes es un criterio de gravedad de la preeclampsia?',opts:['TA sistólica 140 mmHg','Proteinuria de 200 mg/24h','Plaquetas menores de 100.000 o anemia hemolítica microangiopática','Edemas maleolares'],ans:2,exp:'<b>Correcto:</b> Entre los criterios de gravedad de la preeclampsia están: TA sistólica >160, diastólica >110, proteinuria ≥2g/24h, plaquetas <100.000, elevación de enzimas hepáticas, cefalea intensa, oliguria, edema pulmonar y síndrome de HELLP. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_58',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es el tratamiento de elección como profilaxis de las convulsiones en la preeclampsia?',opts:['Diazepam intravenoso','Fenitoína','Sulfato de magnesio intravenoso','Nifedipino oral'],ans:2,exp:'<b>Correcto:</b> El sulfato de magnesio intravenoso es el tratamiento de elección en la profilaxis de las convulsiones en la preeclampsia. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_59',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es el antídoto en caso de intoxicación por sulfato de magnesio?',opts:['Gluconato cálcico (1g IV)','Bicarbonato sódico','Naloxona','Fisostigmina'],ans:0,exp:'<b>Correcto:</b> El antídoto de la intoxicación por sulfato de magnesio es el gluconato cálcico (1g IV). <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_60',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es el tratamiento hipotensor de elección en la preeclampsia ambulatoria leve?',opts:['Hidralacina parenteral','Nifedipino','Alfametildopa oral','Labetalol IV'],ans:2,exp:'<b>Correcto:</b> La alfametildopa oral es el tratamiento de elección ambulatorio en casos leves de preeclampsia por su acción lenta y seguridad. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_61',type:'mc',diff:'easy',sub:'ginecologia',text:'¿Qué antihipertensivos están contraindicados en la gestación?',opts:['Alfametildopa e hidralacina','IECAS (teratogénicos, pueden producir oligoamnios, CIR o fallo renal)','Labetalol y nifedipino','Todos los betabloqueantes'],ans:1,exp:'<b>Correcto:</b> Los IECAS están contraindicados en la gestación porque son teratogénicos y pueden producir oligoamnios, CIR o fallo renal. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_62',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuándo se finaliza la gestación en la preeclampsia grave con edad gestacional menor de 34 semanas?',opts:['Siempre de inmediato independientemente de la situación','Manejo conservador hasta las 34 semanas salvo empeoramiento materno o fetal','Se espera siempre hasta las 37 semanas','Se realiza cesárea urgente siempre'],ans:1,exp:'<b>Correcto:</b> Ante preeclampsia con <34 semanas se realiza manejo conservador hasta las 34 semanas (antes si se confirma madurez pulmonar o empeora la situación maternofetal). <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_63',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Qué reflejo desencadena el despegamiento de las membranas (maniobra de Hamilton) y qué mecanismo produce el inicio del parto?',opts:['Reflejo de Moro; liberación de oxitocina fetal','Reflejo de Ferguson; liberación de prostaglandinas al torrente sanguíneo','Reflejo de succión; liberación de prolactina','Reflejo de Fergusson; liberación de cortisol materno'],ans:1,exp:'<b>Correcto:</b> La maniobra de Hamilton (despegamiento de membranas) desencadena el parto mediante el reflejo de Ferguson y una liberación importante de prostaglandinas. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_64',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuánto mide el diámetro conjugado obstétrico verdadero y para qué se utiliza?',opts:['12 cm; dilatación cervical','10,5 cm; encajamiento de la cabeza fetal','11 cm; estimación del peso fetal','9 cm; rotación de la cabeza'],ans:1,exp:'<b>Correcto:</b> El diámetro conjugado obstétrico va del promontorio al punto más posterior del pubis, mide 10,5 cm y es el que utiliza la cabeza para su encajamiento. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_65',type:'mc',diff:'easy',sub:'ginecologia',text:'¿Qué es la estática fetal y con qué parámetros se describe?',opts:['Posición del cordón umbilical; largo o corto','La colocación del feto intraútero; actitud, situación, presentación y posición','El tamaño fetal en función de la edad gestacional','El movimiento fetal en las últimas semanas'],ans:1,exp:'<b>Correcto:</b> La estática fetal es la colocación del feto intraútero y se describe por la actitud, situación, presentación y posición. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_66',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuáles son los requisitos para la aplicación del fórceps?',opts:['Dilatación mayor de 5 cm, bolsa íntegra, presentación de nalgas','Dilatación completa, bolsa rota, presentación cefálica con cabeza encajada en III plano y anestesia','Dilatación de 3 cm, bolsa íntegra, presentación cefálica en I plano','Solo requiere dilatación completa y presentación cefálica'],ans:1,exp:'<b>Correcto:</b> Para aplicar el fórceps se requiere dilatación completa, bolsa rota, presentación cefálica con cabeza encajada en III plano de Hodge, ausencia de hidrocefalia y anestesia. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_67',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es la indicación actual de la presentación podálica en cuanto a la vía del parto?',opts:['Siempre parto vaginal','Siempre cesárea electiva en general, aunque existen protocolos que permiten parto vaginal en condiciones ideales','Solo cesárea si hay sufrimiento fetal','Parto vaginal hasta las 34 semanas'],ans:1,exp:'<b>Correcto:</b> Actualmente la presentación podálica es indicación general de cesárea electiva, aunque existen protocolos que permiten el parto vaginal en condiciones ideales muy específicas. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_68',type:'mc',diff:'easy',sub:'ginecologia',text:'¿Cuál de los siguientes es una indicación de cesárea electiva?',opts:['Presentación cefálica sin sufrimiento fetal','Placenta previa oclusiva total','Preeclampsia leve','Diabetes gestacional controlada'],ans:1,exp:'<b>Correcto:</b> La placenta previa oclusiva total es una indicación absoluta de cesárea electiva. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_69',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es la definición de amenaza de parto pretérmino?',opts:['Parto antes de la semana 37 consumado','Proceso clínico sintomático que podría conducir a un parto entre las semanas 22 y 37 si no se trata','Cualquier contracción uterina antes de la semana 40','Rotura de membranas antes del inicio del parto'],ans:1,exp:'<b>Correcto:</b> La amenaza de parto pretérmino (APP) es el proceso clínico sintomático que, sin tratamiento o cuando fracasa, podría conducir a un parto entre la semana 22 y 37. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_70',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es el marcador bioquímico con mayor utilidad clínica en el diagnóstico de la amenaza de parto pretérmino?',opts:['Interleucina-6 en líquido amniótico','Fibronectina fetal (elevado VPN)','Proteína C reactiva','Alfafetoproteína sérica materna'],ans:1,exp:'<b>Correcto:</b> La fibronectina fetal tiene un elevado valor predictivo negativo: su ausencia en el exudado vaginal hace altamente improbable el parto pretérmino. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_71',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es el tocolítico de primera elección actual en España para la amenaza de parto pretérmino?',opts:['Ritodrine','Nifedipino','Indometacina','Atosibán'],ans:3,exp:'<b>Correcto:</b> Las directrices de la SEGO recomiendan el atosibán (antagonista de oxitocina) como fármaco de primera línea por su eficacia similar a los beta-agonistas y menores efectos secundarios maternos. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_72',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuáles son los efectos secundarios de los betamiméticos en el parto pretérmino?',opts:['Bradicardia e hipoglucemia','Taquicardia, temblores, descompensación glucémica y alteración tiroidea (por unión a receptores beta-1)','Cierre del ductus arterioso','Oligoamnios'],ans:1,exp:'<b>Correcto:</b> Los betamiméticos (ritodrine) producen efectos secundarios por unión a receptores beta-1: taquicardia, temblores, descompensación glucémica y alteración tiroidea. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_73',type:'mc',diff:'medium',sub:'ginecologia',text:'¿A qué semanas de gestación se recomienda administrar corticoides antenatales para maduración pulmonar fetal?',opts:['22 a 28 semanas','24+0 a 34+6 semanas','28 a 36 semanas','30 a 37 semanas'],ans:1,exp:'<b>Correcto:</b> Se recomienda administrar corticoides antenatales entre las 24+0 y 34+6 semanas de gestación para acelerar la madurez pulmonar y reducir el distrés respiratorio. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_74',type:'mc',diff:'easy',sub:'ginecologia',text:'¿Cuál es el corticoide de elección para la maduración pulmonar fetal antenatal y por qué?',opts:['Dexametasona, porque no atraviesa la placenta','Betametasona, porque atraviesa la placenta y llega al feto','Prednisona, por menor riesgo de efectos secundarios','Hidrocortisona, por mayor potencia antiinflamatoria'],ans:1,exp:'<b>Correcto:</b> La betametasona es el corticoide de elección porque atraviesa la placenta y llega al feto, a diferencia de otros corticoides que son inactivados por enzimas placentarias. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_75',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Qué beneficio ha demostrado el sulfato de magnesio administrado en gestantes entre 24 y 32 semanas ante sospecha de parto pretérmino inminente?',opts:['Retrasar el parto más de 7 días','Disminuir el riesgo de parálisis cerebral y otras alteraciones neurológicas en el neonato','Reducir la necesidad de corticoides','Inhibir las contracciones uterinas de forma eficaz'],ans:1,exp:'<b>Correcto:</b> El sulfato de magnesio administrado en gestantes de 24-32 semanas ha demostrado disminuir el riesgo de parálisis cerebral y alteraciones neurológicas neonatales. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_76',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Qué porcentaje de los casos de RPM ocurre a término y qué sucede en la mayoría en las primeras 48 horas?',opts:['20% a término; requieren cesárea urgente','80% a término; en el 90% de los casos el parto se inicia en 48 horas','50% a término; requieren tocólisis','60% a término; requieren amnioinfusión'],ans:1,exp:'<b>Correcto:</b> Aproximadamente el 80% de los casos de RPM ocurren a término y van seguidos del inicio del parto en cerca del 90% de las ocasiones en un plazo de 48 horas. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_77',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuáles son los criterios diagnósticos de corioamnionitis?',opts:['Solo fiebre materna mayor de 38°C','Fiebre materna más al menos dos de: taquicardia materna, taquicardia fetal, irritabilidad uterina, leucocitosis, líquido amniótico purulento','Líquido amniótico purulento como único criterio','Leucocitosis mayor de 20.000 como único criterio'],ans:1,exp:'<b>Correcto:</b> Los criterios diagnósticos de corioamnionitis son: fiebre materna y al menos dos de los siguientes: taquicardia materna, taquicardia fetal, irritabilidad uterina, leucocitosis materna o líquido amniótico purulento/maloliente. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_78',type:'mc',diff:'easy',sub:'ginecologia',text:'¿Cuál es el tratamiento de la corioamnionitis?',opts:['Tocólisis y corticoides','Finalización de la gestación bajo cobertura antibiótica, independientemente de la semana gestacional','Antibióticos y expectante hasta las 34 semanas','Solo antibióticos intravenosos sin finalizar gestación'],ans:1,exp:'<b>Correcto:</b> El diagnóstico de corioamnionitis es indicación de finalización de la gestación bajo cobertura antibiótica, independientemente de la semana gestacional. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_79',type:'mc',diff:'easy',sub:'ginecologia',text:'¿Cómo se define el embarazo postérmino y cuál es su incidencia?',opts:['Mayor de 40 semanas; 1-2%','Más de 42 semanas; 5-15%','Más de 41 semanas; 20-25%','Más de 43 semanas; 1%'],ans:1,exp:'<b>Correcto:</b> El embarazo postérmino es aquel que sobrepasa la semana 42 y su incidencia es del 5-15%. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_80',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuándo se activa la inducción del parto postérmino y qué agente se usa si el Bishop es mayor o igual a 5?',opts:['Semana 40; prostaglandinas','Semana 41-42; oxitocina directamente si Bishop ≥5','Semana 43; solo cesárea','Semana 40; oxitocina independientemente del Bishop'],ans:1,exp:'<b>Correcto:</b> La inducción se realiza entre la semana 41-42; si el Bishop es ≥5, el cérvix está maduro y se administra oxitocina directamente. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_81',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es la principal causa de morbimortalidad neonatal en los embarazos gemelares?',opts:['Malformaciones congénitas','Síndrome de transfusión feto-fetal','Prematuridad','Prolapso de cordón'],ans:2,exp:'<b>Correcto:</b> La prematuridad es la principal causa de morbimortalidad neonatal en los embarazos gemelares. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_82',type:'mc',diff:'medium',sub:'ginecologia',text:'En los gemelos monocigotos, ¿cuándo se produce la división que da lugar a la gestación monocorial biamniótica (la más frecuente)?',opts:['Antes de las 72 horas (fase de mórula)','Entre los días 4-8 (fase de blastocisto precoz)','Entre los días 8-14','Después del día 13'],ans:1,exp:'<b>Correcto:</b> La división monocorial biamniótica (65% de los monocigotos) ocurre en la fase de blastocisto precoz, entre los días 4-8 tras la fecundación. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_83',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Qué condición gestacional gemelar requiere cesárea electiva de forma obligatoria?',opts:['Gemelos dicigotos biamnióticos con ambos en cefálica','Gemelos monoamnióticos','Gemelos con primer gemelo cefálico de 35 semanas','Gemelos dicigotos con uno en podálica a las 33 semanas'],ans:1,exp:'<b>Correcto:</b> Los gemelos monoamnióticos requieren cesárea electiva de forma obligatoria. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_84',type:'mc',diff:'easy',sub:'ginecologia',text:'¿Cuál es la causa más frecuente de hemorragia puerperal precoz?',opts:['Lesiones del canal del parto','Restos placentarios','Atonía uterina (50%)','Coagulopatías'],ans:2,exp:'<b>Correcto:</b> La atonía uterina es la causa más frecuente de hemorragia puerperal precoz (50%). <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_85',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Qué síndrome puede producirse como consecuencia de una hemorragia puerperal grave por depleción brusca de volumen?',opts:['Síndrome de Asherman','Síndrome de Sheehan (necrosis hipofisaria con hipogalactia, amenorrea, insuficiencia suprarrenal)','Síndrome de Cushing','Síndrome de Turner'],ans:1,exp:'<b>Correcto:</b> El síndrome de Sheehan es la necrosis hipofisaria posparto por depleción brusca de volumen; cursa con hipogalactia, amenorrea, insuficiencia suprarrenal e hipotiroidismo. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_86',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es la primera causa de fiebre en el posparto y cuál el factor de riesgo más importante?',opts:['Mastitis; la lactancia','Endometritis; la cesárea','Infección urinaria; la sonda vesical','Tromboflebitis; la inmovilización'],ans:1,exp:'<b>Correcto:</b> La endometritis es la primera causa de fiebre en el posparto; la cesárea es el factor más importante. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_87',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es el tratamiento de la mastitis puerperal?',opts:['Suspensión inmediata de la lactancia y antibioterapia oral','Calor local, restricción hídrica, vaciamiento mamario y antibioticoterapia (cloxacilina)','Solo antiinflamatorios orales','Drenaje quirúrgico inmediato'],ans:1,exp:'<b>Correcto:</b> El tratamiento de la mastitis consiste en calor local, restricción hídrica, vaciamiento mamario y antibioticoterapia con cloxacilina (cubre S. aureus). <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_88',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es el fármaco de elección para la inhibición de la lactancia?',opts:['Bromocriptina','Cabergolina','Metoclopramida','Ocitocina nasal'],ans:1,exp:'<b>Correcto:</b> El fármaco de elección para la inhibición de la lactancia es la cabergolina (agonista dopaminérgico); de segunda elección se usa la bromocriptina. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_89',type:'mc',diff:'easy',sub:'ginecologia',text:'¿Qué vacunas están contraindicadas durante el embarazo?',opts:['Hepatitis B recombinante y antitetánica','Vacunas con virus o bacterias vivas (sarampión, rubéola, parotiditis, viruela, Sabin, fiebre amarilla, varicela)','Antigripal y antineumocócica','Hepatitis A y anticolérica'],ans:1,exp:'<b>Correcto:</b> Están contraindicadas en el embarazo las vacunas con gérmenes vivos atenuados: sarampión, rubéola, parotiditis, viruela, Sabin, fiebre amarilla y varicela. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_90',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es la dosis de ácido fólico recomendada antes de la concepción y durante el primer trimestre para prevenir defectos del tubo neural?',opts:['4 mg/día','0,4 mg/día iniciado 1 mes antes de la concepción','2 mg/día solo durante el embarazo','0,1 mg/día durante todo el embarazo'],ans:1,exp:'<b>Correcto:</b> Se debe dar ácido fólico 0,4 mg/día comenzando 1 mes antes de la concepción y durante el primer trimestre para prevenir defectos del tubo neural. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_91',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuáles son los fármacos de categoría X (absolutamente contraindicados en el embarazo)?',opts:['Heparina, insulina y paracetamol','Ribavirina, metotrexate, isotretinoína y andrógenos','IECAS y diuréticos','Tetraciclinas y quinolonas'],ans:1,exp:'<b>Correcto:</b> Los fármacos de categoría X (nunca deben administrarse en gestación) son: ribavirina, metotrexate, isotretinoína y derivados de vitamina A, y andrógenos. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_92',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Qué antimicrobiano está contraindicado durante todo el embarazo?',opts:['Penicilina','Cefalosporinas','Quinolonas','Macrólidos'],ans:2,exp:'<b>Correcto:</b> Las quinolonas están contraindicadas durante todo el embarazo por su efecto sobre el cartílago fetal. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_93',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Por qué está contraindicada la estreptomicina durante el embarazo?',opts:['Produce malformaciones cardíacas','Es el único aminoglucósido que ha demostrado ototoxicidad fetal (sordera congénita)','Produce cierre del ductus arterioso','Es teratogénica en el primer trimestre'],ans:1,exp:'<b>Correcto:</b> La estreptomicina está contraindicada durante el embarazo porque es el único aminoglucósido que ha demostrado ototoxicidad, pudiendo producir sordera congénita. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_94',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Qué efecto puede producir el litio durante la gestación?',opts:['Defectos del tubo neural','Anomalías cardiovasculares (anomalía de Ebstein), bocio y fisura palatina','Sindactilia y manchas dentarias','Retraso mental y alteraciones esqueléticas'],ans:1,exp:'<b>Correcto:</b> El litio puede producir anomalías cardiovasculares importantes (anomalía de Ebstein), bocio y fisura palatina. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_95',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es el efecto del dietilestilbestrol cuando se administra durante la gestación?',opts:['Malformaciones cardiacas en el feto','Adenocarcinoma de células claras en vagina y cérvix del feto hembra','Defectos del tubo neural','Hipoplasia pulmonar fetal'],ans:1,exp:'<b>Correcto:</b> El dietilestilbestrol produce adenocarcinoma de células claras en vagina y cérvix del feto hembra. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_96',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es la complicación más específica del síndrome de transfusión feto-fetal en el gemelo receptor?',opts:['CIR y oligoamnios','Hipervolemia, HTA, policitemia, polihidramnios e insuficiencia cardíaca de alto gasto','Anemia y CIR','Hidropesía fetal aislada'],ans:1,exp:'<b>Correcto:</b> El feto receptor en el síndrome de transfusión feto-fetal desarrolla hipervolemia, HTA, policitemia, polihidramnios e insuficiencia cardíaca de alto gasto. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_97',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuándo se forman los gemelos siameses en función del momento de división del embrión monozigótico?',opts:['Antes de las 72 horas (mórula)','Entre los días 4-8 (blastocisto precoz)','Entre los días 8-14 (blastocisto tardío)','Después del día 13, cuando ya está formado el disco embrionario'],ans:3,exp:'<b>Correcto:</b> Los gemelos siameses se forman cuando la división se produce a partir del día 13, cuando ya está formado el disco embrionario. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_98',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es el manejo del CIR tipo II a término (≥37 semanas) cuando la onda diastólica umbilical está conservada y el líquido amniótico es normal?',opts:['Cesárea urgente inmediata','Se puede diferir el parto hasta que el Bishop sea adecuado sin superar las 40 semanas','Tocólisis hasta la semana 40','Inducción inmediata con prostaglandinas'],ans:1,exp:'<b>Correcto:</b> Si el Doppler umbilical muestra onda diastólica conservada y el líquido amniótico es normal a término, el parto puede diferirse hasta que el test de Bishop sea adecuado sin superar las 40 semanas. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_99',type:'mc',diff:'medium',sub:'ginecologia',text:'¿A partir de qué semana de gestación no cabe esperar beneficio de prolongar la gestación en la amenaza de parto pretérmino?',opts:['Semana 30','Semana 32','Semana 34 (incluyendo esta semana)','Semana 36'],ans:2,exp:'<b>Correcto:</b> Desde las 34 semanas (incluyendo esta semana) no cabe esperar beneficio de prolongar la gestación y se puede permitir la evolución del parto. <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'},
{id:'g1_100',type:'mc',diff:'medium',sub:'ginecologia',text:'¿Cuál es la causa más frecuente de muerte materna en el puerperio?',opts:['Infección puerperal','Tromboembolismo pulmonar','Hemorragia (CID, abruptio)','Eclampsia'],ans:2,exp:'<b>Correcto:</b> La causa más frecuente de muerte materna es la hemorragia (CID, abruptio placentae). <i>Ref: Manual AMIR Ginecología y Obstetricia.</i>'}
];
